"""
MKT Original Language Commentary — 1 Chronicles chapters 16–18
Run: python3 scripts/zc-original-1chronicles-16-18.py

Source data used:
- data/interlinear/1chronicles.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/1chronicles.json

Key decisions in this range:
- Ch16: The composite psalm (Pss 105:1-15, 96:1-13, 106:1, 47-48) — noted
  where the Chronicler adapts psalm texts and what the adaptations reveal
- v22: mᵉšîḥay (my anointed ones) — plural form explained; not messianic
  in the later sense but the term's semantic field is noted
- v34: ḥesed (steadfast love/covenant loyalty) — the primary translation
  issue throughout the psalm
- Ch17: 'I will build you a house' — the house wordplay central to the passage;
  v14 'my kingdom' vs 2 Sam 7:16 'your kingdom' — a deliberate Chronicler
  theological revision emphasizing divine ownership
- v13: Father-son formula and its relation to Ps 2:7; Heb 1:5
- v17: MT's difficult ûrᵉʾîtanî kᵉtôr hāʾādām — explained with options
- Ch18: mišpāṭ ûṣedāqāh (v14) — the governance-legitimacy formula for
  the ideal Davidic king
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON1 = {
  "16": {
    "1": "<p>The ark is placed inside the tent (<em>ʾōhel</em>) David pitched — not the Mosaic tabernacle (<em>mišķān</em>), which remains at Gibeon (v39). This creates the two-sanctuary situation unique to David's reign: the ark without the tabernacle. The offerings here — <em>ʿōlōt</em> (burnt offerings) and <em>šᵉlāmîm</em> (peace/fellowship offerings) — are both required for covenant-inaugural ceremonies (cf. Exod 24:5).</p>",
    "2": "<p>David blesses the people <em>bᵉšēm YHWH</em> — in the name of YHWH. The verb <em>bārak</em> (to bless) in the piel, used of a king blessing the people, recalls Solomon's blessing at the temple dedication (1 Kgs 8:55-56) and Moses blessing Israel (Deut 33:1). Only priests typically blessed the assembly (Num 6:22-27); David's priestly-kingly role here is significant for the Chronicler's portrait.</p>",
    "3": "<p>The distribution of food: <em>kikkār leḥem</em> (a loaf of bread), <em>ešpār</em> (a cut of meat — the term appears only here and 2 Sam 6:19, likely a specific cut or portion), and <em>ʾăšîšāh</em> (raisin cake, associated with festive celebration, cf. Song 2:5). The communal meal following a covenant ceremony signals the completion of the event and the people's full incorporation into the celebration.</p>",
    "4": "<p>David appoints Levites to minister (<em>lᵉšārēt</em>) before the ark — three functions: <em>lᵉhazķîr</em> (to invoke, lit. &ldquo;to cause to remember&rdquo; — possibly a type of petition-prayer), <em>lᵉhôdôt</em> (to give thanks — hiphil of <em>yādāh</em>), and <em>lᵉhallēl</em> (to praise — piel of <em>hālal</em>). These three liturgical acts frame the psalm that follows and define the theological purpose of the Davidic worship establishment.</p>",
    "5": "<p>Asaph as chief (<em>hārōʾš</em>) of the Levitical worship ministers — the same Asaph after whom twelve of the psalms are titled (Pss 50, 73-83). The assignment of Obed-edom (cf. ch13) to a musical role here rehabilitates a figure who had hosted the ark; his family became a permanent fixture in the Jerusalem temple establishment.</p>",
    "6": "<p>The two priests, Benaiah and Jahaziel, are assigned <em>taʿăśe baḥăṣōṣᵉrôt</em> — to sound the trumpets (<em>ḥăṣôṣᵉrôt</em>) continually. The <em>ḥăṣōṣᵉrāh</em> (silver trumpet) was a distinctly priestly instrument (Num 10:1-10), different from the shofar; its continuous sounding marked the ongoing liturgical presence of the ark. The dual assignees mirrors the two silver trumpets of Num 10:2.</p>",
    "7": "<p><em>Bᵉyôm hahûʾ bāz dāwîd lᵉrōʾš lᵉhôdôt laYHWH bᵉyad-ʾĀsāp wᵉʾeḥāyw</em> — on that day David first appointed Asaph and his brothers. The word <em>bāz</em> (then, at that time) marks the occasion as the inaugural moment of the Davidic liturgical arrangement. The psalm that follows (vv8-36) is presented as the foundational act of worship — composed or assembled by David, delivered through Asaph.</p>",
    "8": "<p><em>hôdû laYHWH qirᵉʾû bišmô</em> — Give thanks to the LORD, call on his name. This opening matches Ps 105:1 almost verbatim. <em>hôdû</em> is the hiphil imperative of <em>yādāh</em>, a verb whose root meaning includes &ldquo;to throw/cast&rdquo; and has developed the theological sense of acknowledging what is true about someone — here, YHWH's acts. <em>hôdîʿû bāʿammîm ʿălîlôtāyw</em> — make known his deeds among the peoples: the proclamation is explicitly universal in scope from the first verse.</p>",
    "9": "<p><em>šîrû-lô zammᵉrû-lô</em> — sing to him, make music to him. The two imperatives pair singing (<em>šîr</em>) with instrumental/melodic performance (<em>zāmar</em> in the piel, associated with skilled musical playing). <em>śîḥû</em> — meditate on/tell of (<em>śîaḥ</em>, to talk about, reflect on) — his wondrous works (<em>niplᵉʾōtāyw</em>, the niphal participle = things made wonderful).</p>",
    "10": "<p><em>hithallᵉlû bᵉšēm qodsô</em> — glory/boast in his holy name. The hithpael of <em>hālal</em> is reflexive boasting — the worshiper acknowledges that YHWH's name is the proper object of pride, redirecting the human impulse to self-glorification. <em>yiśmah lēb mᵉḇaqᵉšê YHWH</em> — let the heart of those who seek YHWH rejoice: the participle <em>mᵉḇaqᵉšê</em> (those seeking) is the continuous active seeking that characterizes the covenant community.</p>",
    "11": "<p><em>dirᵉšû YHWH wᵉʿuzzô</em> — seek the LORD and his strength. Two near-synonyms: <em>dāraš</em> (to seek, inquire, require) and the following <em>baqqᵉšû</em> (seek, look for) — the pairing emphasizes active, persistent seeking. <em>ʿuzzô</em> (his strength) in context likely refers to the ark as the physical locus of divine power (cf. Ps 78:61, where the ark is called &ldquo;his strength&rdquo;). <em>paḇqᵉšû pānāyw tāmîd</em> — seek his presence (<em>pānāyw</em> = his face) continually.</p>",
    "12": "<p><em>niflᵉʾōtāyw ʾăšer ʿāśāh mōpᵉtāyw ûmišpᵉṭê-pîhû</em> — his wondrous works, his miracles, and the judgments of his mouth. Three terms for divine acts: <em>niplāʾôt</em> (wonders, amazing acts), <em>môpᵉtîm</em> (signs, portents — typically miraculous signs confirming a prophetic word), and <em>mišpᵉṭê pîhû</em> (judgments of his mouth — spoken divine verdicts). The phrase surveys the full range of YHWH's self-revelation in history.</p>",
    "13": "<p><em>zeraʿ Yiśrāʾēl ʿaḇdô bᵉnê Yaʿăqōḇ bᵉḥîrāyw</em> — offspring of Israel his servant, children of Jacob, his chosen ones. <em>ʿeḇed</em> (servant) — Israel is YHWH's <em>ʿeḇed</em>, a title of honor in covenantal relationship (cf. Abraham in Gen 26:24; David in v7 of this chapter; Isaiah's Servant Songs). <em>bᵉḥîrāyw</em> (his chosen ones) — from <em>bāḥar</em>, the election verb; Israel as the elect nation.</p>",
    "14": "<p><em>hûʾ YHWH ʾĕlōhênû bᵉḵol-hāʾāreṣ mišpāṭāyw</em> — He is the LORD our God; his judgments are in all the earth. The first clause is a covenant identification formula (<em>hûʾ ʾĕlōhênû</em> = he is our God) that echoes the Shema structure. The second clause asserts universal scope: YHWH's governance (<em>mišpāṭîm</em>) is not limited to Israel but extends over all the earth.</p>",
    "15": "<p><em>zikrû lᵉʿôlām bᵉrîtô</em> — remember his covenant forever. <em>bᵉrît</em> (covenant) is the key term of the entire psalm; the rest of the psalm (vv16-18) specifies its content. <em>dāḇār ṣiwwāh lᵉʾelep dôr</em> — the word commanded for a thousand generations: the number &ldquo;thousand generations&rdquo; is a hyperbole of permanence, echoing the Decalogue (Exod 20:6; Deut 7:9).</p>",
    "16": "<p><em>ʾăšer kārat ʾet-ʾAḇrāhām ûšᵉḇûʿātô lᵉYiṣḥāq</em> — the covenant he cut (<em>kārat</em>, the standard idiom for making a covenant, lit. &ldquo;to cut&rdquo;) with Abraham and his sworn oath to Isaac. <em>šᵉḇûʿāh</em> (oath) is the self-binding promise by which a covenant is sealed — YHWH swears by himself (cf. Gen 22:16; Heb 6:13) since there is no greater authority by which to swear.</p>",
    "17": "<p><em>wayyaʿămîdehā lᵉYaʿăqōḇ lᵉḥōq lᵉYiśrāʾēl bᵉrît ʿôlām</em> — he confirmed it to Jacob as a statute, to Israel as an everlasting covenant. <em>hēqîm</em> (hiphil of <em>qûm</em>) = to establish, make stand firm — the verb used throughout the OT for the confirmation and guarantee of a covenant promise. <em>ḥōq</em> (statute) here elevates the covenant promise to the status of law — something bound by divine decree, not merely verbal promise.</p>",
    "18": "<p><em>lᵉḵā ʾettēn ʾet-ʾereṣ kᵉnaʿan ḥeḇel naḥălatkhem</em> — to you I will give the land of Canaan as your portion of inheritance. <em>ḥeḇel</em> (measuring line, portion) — the land is described as a measured allotment, a surveyor's portion. The Promised Land as <em>naḥălāh</em> (inheritance/patrimony) is the standard covenantal term for the land-grant; inheritance language implies permanent familial ownership, not temporary occupation.</p>",
    "19": "<p><em>bihyôtᵉkem mᵉtê mispar kimᵉʿaṭ wᵉgārîm bāh</em> — when you were few in number, of little account, and strangers in it. The two terms: <em>mᵉtê mispar</em> (men of number = countable, i.e., few) and <em>gārîm</em> (sojourners/strangers — the <em>gēr</em> status, those without land rights). The contrast with Israel's later population and land ownership makes the faithfulness of YHWH more striking: the promise was given when Israel had nothing.</p>",
    "20": "<p><em>wayyithalᵉkû miggôy ʾel-gôy ûmimmamlaḵāh ʾel-ʿam ʾaḥēr</em> — they wandered from nation to nation, from one kingdom to another people. The hithpael of <em>hālaḵ</em> (to walk) in the reflexive/iterative sense describes the patriarchal wandering — nomadic, displacement, vulnerability. The repeated <em>miggôy ʾel-gôy</em> (from nation to nation) emphasizes the contrast with YHWH's faithfulness across that wandering.</p>",
    "21": "<p><em>lōʾ-hinnîaḥ ʾādām lᵉʿošqām</em> — he allowed no man to oppress them. <em>ʿāšaq</em> (to oppress, exploit, crush) — the term used for oppression of the weak in the covenant law texts (Lev 19:13; Deut 24:14). YHWH's protection during the patriarchal period is framed as active legal advocacy — he &ldquo;rebuked kings on their account&rdquo; (note the extraordinary claim that even Pharaoh was rebuked by YHWH before Moses's time, cf. Gen 12:17; 20:3).</p>",
    "22": "<p><em>ʾal-tiggᵉʿû bimšîḥāy wûḇinḇîʾay ʾal-tārēʿû</em> — do not touch my anointed ones, and to my prophets do no harm. <em>mᵉšîḥāy</em> (my anointed ones) is plural — the patriarchs are the referents in context (Ps 105:15). The term <em>māšîaḥ</em> (anointed) at this stage applies to those whom YHWH has set apart for a special role; the singular messianic use develops later. <em>nāḇîʾ</em> (prophet) — the patriarchs as prophets is explicit in Gen 20:7 (Abraham).</p>",
    "23": "<p><em>šîrû laYHWH kol-hāʾāreṣ</em> — sing to the LORD, all the earth! This verse begins the Psalm 96 section of the composite psalm (Ps 96:1-13). The shift from Ps 105's historical rehearsal to Ps 96's universal summons marks a climax: having recalled what YHWH has done for Israel, the psalm now calls all creation to respond. <em>baśśᵉrû miyyôm-ʾel-yôm yᵉšûʿātô</em> — proclaim his salvation day to day: <em>baśar</em> (to bring good news, announce — the root of <em>bᵉśôrāh</em>, good news/gospel).</p>",
    "24": "<p><em>sappᵉrû ḇagôyim kᵉḇôdô bᵉḵol-hāʿammîm niplᵉʾōtāyw</em> — declare his glory among the nations, his marvelous works among all peoples. The Chronicler preserves the universalist vision of Ps 96 intact: YHWH's <em>kāḇôd</em> (glory, weighty presence) is for all nations, not Israel alone. This is the theological framework for the temple that follows in 1 Chr 28-29: Solomon's temple is to be a house of prayer for all peoples (cf. Isa 56:7).</p>",
    "25": "<p><em>kî gādôl YHWH ûmᵉhullāl mᵉʾōd wᵉnôrāʾ hûʾ ʿal-kol-ʾĕlōhîm</em> — for great is the LORD and greatly to be praised; he is to be feared above all gods. <em>mᵉhullāl</em> — pual participle of <em>hālal</em> = worthy of praise, praiseworthy (the passive: one to whom praise is properly directed). <em>nôrāʾ</em> (feared, awesome) — the niphal participle of <em>yārēʾ</em>, describing YHWH's numinous quality that evokes reverent awe.</p>",
    "26": "<p><em>kî kol-ʾĕlōhê hāʿammîm ʾĕlîlîm wîhwāh šāmayim ʿāśāh</em> — for all the gods of the peoples are idols (<em>ʾĕlîlîm</em>), but the LORD made the heavens. The word <em>ʾĕlîlîm</em> is a diminutive or pejorative derived from <em>ʾēl</em> (God), suggesting &ldquo;worthless little gods&rdquo; — the same root used in the prophets for images that are nothing (Isa 2:8, 18; 10:10-11). The contrast: the gods of the nations did not make the heavens; YHWH did.</p>",
    "27": "<p><em>hôd wᵉhādār lᵉpānāyw ʿōz wᵉḥedwāh bimqômô</em> — splendor and majesty before him; strength and joy in his place/dwelling. The four terms form two pairs: <em>hôd</em> (majesty, a quality of royalty, cf. Ps 21:6) and <em>hādār</em> (splendor, honor, adornment); <em>ʿōz</em> (strength, power) and <em>ḥedwāh</em> (joy, gladness). The Chronicler substitutes <em>ḥedwāh</em> (joy) where Ps 96:6 has <em>tipreret</em> (glory/beauty) — a small but theologically significant change emphasizing that YHWH's presence is characterized by joy.</p>",
    "28": "<p><em>hāḇû laYHWH mišpᵉḥôt ʿammîm</em> — ascribe to the LORD, O families of the peoples. The verb <em>yāhab</em> (imperative <em>hāḇû</em>) means &ldquo;give, render, ascribe&rdquo; — a term of attribution. <em>mišpᵉḥôt ʿammîm</em> (families/clans of the peoples) addresses all human kindreds, not just Israel — the universal scope of the summons is maintained throughout the Ps 96 section.</p>",
    "29": "<p><em>hāḇû laYHWH kᵉḇôd šᵉmô</em> — ascribe to the LORD the glory due his name. <em>kᵉḇôd šᵉmô</em> (the glory of his name) — <em>kāḇôd</em> is both the inherent weighty glory that belongs to YHWH and the reputation/honor that humans acknowledge. <em>wᵉhišταḥăwû laYHWH bᵉhadrat-qōdeš</em> — worship the LORD in the splendor of holiness. <em>hadrat-qōdeš</em> (splendor/beauty of holiness) is ambiguous: it may mean worshiping in holy attire, or in the beauty that holiness brings, or in the holy precincts. The phrase emphasizes that authentic worship has an aesthetic dimension — it is beautiful because holiness is beautiful.</p>",
    "30": "<p><em>ḥîlû mippānāyw kol-hāʾāreṣ</em> — tremble before him (<em>ḥîl</em> — to writhe, to be in travail, to tremble) all the earth. The verb <em>ḥûl/ḥîl</em> connotes the trembling associated with both fear and birth-pangs — a visceral response to divine presence. <em>ʾap-tikkôn têḇēl bal-timmôṭ</em> — the world is firmly established; it cannot be moved: the stability of creation is grounded in YHWH's kingship (cf. Ps 93:1).</p>",
    "31": "<p><em>yiśmᵉḥû haššāmayim wᵉtāgēl hāʾāreṣ</em> — let the heavens be glad, and let the earth rejoice. The jussive forms invite cosmic celebration. <em>wᵉyōmᵉrû ḇagôyim YHWH mālaḵ</em> — and let them say among the nations: &ldquo;The LORD reigns!&rdquo; (<em>mālaḵ</em> — perfect of <em>mālaḵ</em>, &ldquo;to reign&rdquo; — the acclamation formula for a newly enthroned king). The cry <em>YHWH mālaḵ</em> recurs throughout the enthronement psalms (Pss 93:1; 96:10; 97:1; 99:1) and signals the comprehensive sovereignty of YHWH over creation and history.</p>",
    "32": "<p><em>yirʿam hayyām ûmᵉlōʾô</em> — let the sea roar and all it contains. The sea (<em>yām</em>) was associated in ancient Near Eastern cosmology with primordial chaos; its joyful roaring is an inversion — chaos is invited to join creation's praise. <em>yaʿălōz haśśādeh wᵉḵol-ʾăšer-bô</em> — let the field exult and all that is in it: agricultural abundance participates in eschatological praise.</p>",
    "33": "<p><em>ʾāz yᵉrannᵉnû ʿăṣê hayyaʿar mippᵉnê YHWH</em> — then the trees of the forest will sing for joy before the LORD. The particle <em>ʾāz</em> (then, at that time) marks the eschatological moment: when YHWH comes to judge, creation breaks into song. <em>kî-ḇāʾ lišpôṭ ʾet-hāʾāreṣ</em> — for he comes to judge the earth: the coming of YHWH as judge is presented as good news that creation celebrates, not as a threat. Judgment (<em>šāpaṭ</em>) here means establishing righteous order, not merely punishing evil.</p>",
    "34": "<p><em>hôdû laYHWH kî-ṭôḇ kî lᵉʿôlām ḥasdô</em> — give thanks to the LORD, for he is good; for his steadfast love endures forever. This refrain (from Ps 107:1; 118:1, 29; 136:1) is the most repeated single verse in the Hebrew psalter. <em>ḥesed</em> — the single most important word in this verse: variously translated &ldquo;steadfast love,&rdquo; &ldquo;covenant loyalty,&rdquo; &ldquo;lovingkindness,&rdquo; or &ldquo;mercy.&rdquo; It denotes the persistent, covenant-faithful love that refuses to abandon its object regardless of the object's failures — the love that is simultaneously personal affection and legal obligation. The MKT renders it &ldquo;steadfast love&rdquo; throughout.</p>",
    "35": "<p><em>ûmōšîʿēnû wᵉqabbᵉṣēnû min-haggôyim</em> — save us and gather us from among the nations. The two requests use the hiphil of <em>yāšaʿ</em> (save) and the piel of <em>qāḇaṣ</em> (gather). The <em>qāḇaṣ</em> (gather) verb is the standard term for the eschatological regathering of exiled Israel (Isa 40:11; 43:5; Jer 31:10; Ezek 37:21). The presence of this petition in the psalm composed for the ark's installation is theologically striking: even at the moment of triumph, the psalm anticipates future exile and regathering.</p>",
    "36": "<p><em>bārûk YHWH ʾĕlōhê Yiśrāʾēl min-hāʿôlām wᵉʿad-hāʿôlām</em> — Blessed be the LORD, the God of Israel, from everlasting to everlasting. This closing doxology (from Ps 106:48) marks the structural division between the third book and fourth book of the psalter. <em>wāʾōmer kol-hāʿām ʾāmēn ûhallēl laYHWH</em> — all the people said &ldquo;Amen&rdquo; and &ldquo;Praise the LORD.&rdquo; <em>ʾāmēn</em> (so be it, truly) is the congregation's ratification of the doxology; the Chronicler adds the people's response to what is a psalm-closing formula in the psalter.</p>",
    "37": "<p>David leaves Asaph before the ark <em>lišrōt lipnê hāʾārôn tāmîd</em> — to minister before the ark continually (<em>tāmîd</em>). The term <em>tāmîd</em> (continually, perpetually) is the same word used for the <em>ʿōlat hatāmîd</em> (the continual burnt offering, Num 28:3-8) — Asaph's ministry is framed as a liturgical constant parallel to the sacrificial system.</p>",
    "38": "<p>Obed-edom with 68 kin assigned as gatekeepers (<em>šōʿărîm</em>) — a role of honor at the ark's tent. The Obed-edom who hosted the ark for three months (ch13) is now permanently integrated into the ark-ministry staff. <em>šōʿēr</em> (gatekeeper) was a major Levitical role at the sanctuary, controlling access and maintaining the sanctity of the space.</p>",
    "39": "<p>Zadok the priest is stationed at the tabernacle (<em>mišķan YHWH</em>) at the high place of Gibeon — the Mosaic tabernacle without the ark. The split arrangement (Asaph with the ark in Jerusalem, Zadok at the tabernacle in Gibeon) is the Chronicler's explanation of why both sites were legitimate during David's reign: each had its proper component of the full worship apparatus.</p>",
    "40": "<p><em>lᵉhaʿălôt ʿōlôt laYHWH ʿal-mizbah hāʿōlāh tāmîd</em> — to offer burnt offerings to the LORD on the altar of burnt offering continually. The <em>ʿōlat hattāmîd</em> (regular burnt offering) with its twice-daily offering (morning and evening, Num 28:3-8) is maintained at Gibeon. This establishes that the Mosaic sacrificial regulations are being honored even while the ark-worship proceeds separately in Jerusalem.</p>",
    "41": "<p><em>ûʿimmāhem Hêmān wîdûtûn wᵉše ʾār habᵉrûrîm ʾăšer niqqᵉḇû bišēmôt</em> — with them were Heman and Jeduthun and the rest of those chosen and designated by name. <em>bᵉrûrîm</em> (chosen ones — from <em>bārar</em>, to select, purify, choose) suggests careful selection criteria; <em>niqqᵉḇû bišēmôt</em> (designated by name) means officially registered. The repeated precision of appointment underscores the Chronicler's theme: proper worship requires proper personnel, properly authorized.</p>",
    "42": "<p>Heman and Jeduthun had <em>ḥăṣōṣᵉrôt ûmᵉṣillātayim</em> (trumpets and cymbals) and <em>kᵉlê šîr hāʾĕlōhîm</em> — instruments of divine song (lit. &ldquo;instruments of the song of God&rdquo;). The possessive <em>hāʾĕlōhîm</em> (of God) applied to musical instruments is unusual and signals their sacred character. The sons of Jeduthun are assigned as gatekeepers, integrating the musical families into both liturgical and administrative roles.</p>",
    "43": "<p><em>wayyēlᵉkû kol-hāʿām ʾîš lᵉḇêtô</em> — all the people went home, each to his house. The conclusion of the ark-installation ceremony marks the transition from the corporate event to domestic life. David's return to bless his household (<em>lᵉḇārēk ʾet-bêtô</em>) echoes the opening verse — the blessing that began with the ark's installation extends to the domestic sphere.</p>"
  },
  "17": {
    "1": "<p>David reflects on the contrast: he dwells in a house of cedar (<em>bêt ʾărāzîm</em>) while the ark dwells under a tent/curtains (<em>yôšeḇet taḥat yᵉrîʿôt</em> — lit. &ldquo;sitting/dwelling under curtain-cloths&rdquo;). The Solomonic temple later uses cedar extensively (1 Kgs 5-6); the cedar palace (<em>bêt hāʾerez</em>, 2 Sam 5:11) was the pinnacle of royal architecture. David's sense of incongruity is the motivation for what will be the central covenant of the book.</p>",
    "2": "<p>Nathan's initial response — <em>ʿăśēh ʾēt kol-ʾăšer billᵉḇāḇᵉḵā kî hāʾĕlōhîm ʿimmāḵ</em> — do everything in your heart, for God is with you. Nathan gives approval based on his own assessment (<em>ʾāmar</em> without &ldquo;word of the LORD&rdquo;). This immediately precedes a divine reversal: the same night YHWH corrects Nathan's well-intentioned but premature approval, establishing that the prophet's personal judgment must yield to divine word.</p>",
    "3": "<p><em>wayhî ballayᵉlāh hahûʾ wayhî dᵉḇar-ʾĕlōhîm ʾel-Nātān</em> — that same night the word of God came to Nathan. The immediacy (&ldquo;that same night&rdquo;) prevents any possibility that Nathan's approval has standing. The formula <em>dᵉḇar-YHWH</em> (word of the LORD/God) marks authentic prophetic reception — the word that comes to the prophet overrides all prior judgments.</p>",
    "4": "<p><em>lōʾ-ʾattāh tibnel-lî habbayit lāšāḇet</em> — you shall not build a house for me to dwell in. The divine negation is direct and final. The play on <em>bayit</em> (house) begins here: David proposes to build YHWH a <em>bayit</em> (temple); YHWH responds by promising to build David a <em>bayit</em> (dynasty). The word occurs seven times in vv4-14. The negation does not demean David's intention but redirects it toward the next generation.</p>",
    "5": "<p><em>kî lōʾ yāšaḇtî bᵉḇayit miyyôm haʿălōtî ʾet-Yiśrāʾēl ʿad hayyôm hazzeh</em> — I have never dwelt in a house from the day I brought Israel up until this day. YHWH's self-description as one who has moved (<em>wāʾehyeh mēʾōhel ʾel-ʾōhel ûmimmišḵān</em>) from tent to tent and from tabernacle to tabernacle. The terms <em>ʾōhel</em> (tent) and <em>mišḵān</em> (tabernacle, dwelling-place) both appear, acknowledging the Mosaic worship structure while implying that YHWH's presence is not spatially constrained.</p>",
    "6": "<p>YHWH asks rhetorically: did I ever say a word to any of the judges (<em>šōpᵉṭîm</em>) — the Deuteronomistic history's term for Israel's pre-monarchic leaders — asking why they had not built him a cedar house? The implied answer is no: the temple was never YHWH's demand but Solomon's commission. This retroactively addresses any sense that the absence of a temple during the judges period was a failure.</p>",
    "7": "<p><em>kōh tōmar lᵉʿaḇdî lᵉḏāwid</em> — thus says the LORD of hosts: the messenger formula introduces the oracle. <em>ṣᵉḇāʾôt</em> (hosts/armies) — the divine title <em>YHWH ṣᵉḇāʾôt</em> (LORD of Hosts) emphasizes his command over heavenly and earthly armies, particularly appropriate in the context of David's military conquests (ch18). <em>min-hannāweh</em> (from the pasture) — YHWH took David from following the flock (<em>mēʾaḥar haṣṣōʾn</em>) to being prince (<em>nāgîd</em>) — the shepherd-to-king pattern.</p>",
    "8": "<p><em>wāʾehyeh ʿimmᵉḵā bᵉḵōl ʾăšer hālaḵtā</em> — I have been with you wherever you went. This divine accompaniment formula (<em>ʾehyeh ʿimmᵉḵā</em> — I will be/have been with you) echoes the patriarchal covenant language (Gen 26:3; 28:15) and the commission of Moses (Exod 3:12). <em>wᵉʾaḵrittāh ʾet-kol-ʾôyᵉḇeḵā mippānêḵā</em> — I have cut off all your enemies from before you: the hiphil of <em>kārat</em> (to cut off, cut down) — the same verb for making a covenant; YHWH's covenant with David is expressed partly by eliminating his enemies.</p>",
    "9": "<p><em>wᵉśamtî maqôm lᵉʿammî Yiśrāʾēl wᵉnᵉṭaʿtîhû</em> — I will establish a place for my people Israel and plant them. The verb <em>nāṭaʿ</em> (to plant) applied to a people recalls the Exodus-settlement language: Israel is planted in the land as a vine (Ps 80:8-9; Isa 5:1-7). <em>wᵉlōʾ yirgaz ʿôd</em> — they will not be disturbed again: the promise of security is expressed negatively — the absence of the <em>rᵉgaz</em> (trembling, disturbance) that has characterized their existence.</p>",
    "10": "<p><em>wᵉhiknaʿtî ʾet-kol-ʾôyᵉḇeḵā</em> — I will subdue all your enemies. The shift from historical retrospection (vv7-9b) to future promise is marked by waw-consecutive imperfect: <em>wᵉhiknaʿtî</em> (I will humble/subdue). <em>wᵉhiggadtî lāḵ kî-bayit yibne-lᵉḵā YHWH</em> — moreover, I declare to you that the LORD will build you a house: the pivot verse. <em>higgîd</em> (hiphil of <em>nāgad</em>, to declare, announce) is used for authoritative proclamation. The house YHWH promises to build David is a <em>bayit</em> (dynasty), not a building.</p>",
    "11": "<p><em>wᵉhāyāh kî-yimlᵉʾû yāmeḵā lāleḵet ʿim-ʾăḇōteḵā</em> — when the time comes for you to go to be with your ancestors. The idiom <em>lāleḵet ʿim-ʾăḇōteḵā</em> (to go with your fathers) is a euphemism for death without the typical verb <em>mût</em> (to die). <em>wăhăqîmōtî ʾet-zarʿăḵā ʾaḥăreḵā</em> — I will raise up your seed/offspring after you. <em>zeraʿ</em> (seed) is the key term: Abraham received the covenant through his <em>zeraʿ</em> (Gen 17:7-10); David receives the same covenant-language applied now to the royal dynasty.</p>",
    "12": "<p><em>hûʾ yibne-lî bayit wᵉḵōnanᵉtî ʾet-kisʾô ʿad-ʿôlām</em> — he will build a house for me, and I will establish his throne forever. <em>kōnanᵉtî</em> — the piel of <em>kûn</em>, to establish, make firm, set in place. The verb is significant: YHWH himself will be the one to establish the throne — human political skill and military power cannot secure what only divine action can guarantee. <em>ʿad-ʿôlām</em> (forever) appears twice in this oracle (vv12, 14) — the key term of the Davidic covenant's unconditional permanence.</p>",
    "13": "<p><em>ʾănî ʾehyeh-lô lᵉʾāḇ wᵉhûʾ yihyeh-lî lᵉḇēn</em> — I will be his father, and he will be my son. This adoption formula is the most theologically important sentence in ch17. In its immediate context it refers to Solomon; in canonical context it becomes the basis for the NT's identification of Jesus as the eternal Son of God (Ps 2:7; 2 Sam 7:14; Heb 1:5). <em>wᵉḥasdî lōʾ-ʾāsîr mimmennû</em> — I will not remove my steadfast love (<em>ḥesed</em>) from him, as I removed it from Saul. The contrast with Saul is explicit: the Davidic dynasty receives an unconditional <em>ḥesed</em> that the Saulide dynasty never had.</p>",
    "14": "<p><em>wᵉhaʿămadtîhû bᵉḇêtî ûḇᵉmalḵûtî ʿad-hāʿôlām</em> — I will establish him in my house and in my kingdom forever. The Chronicler substitutes <em>malḵûtî</em> (my kingdom) for 2 Sam 7:16's <em>malḵûtᵉḵā</em> (your kingdom). This is a deliberate theological revision: the Chronicler emphasizes that the kingdom belongs to YHWH, not to David. David and his dynasty are stewards of a divine kingdom, not proprietors of a human one. The permanent throne (<em>kisʾô yihyeh nāḵôn ʿad-ʿôlām</em>) is the Davidic throne understood as the earthly manifestation of YHWH's own sovereign rule.</p>",
    "15": "<p>Nathan delivered the vision (<em>ḥāzôn</em>) — the same noun used for prophetic visions in Isa 1:1, Nah 1:1. The entire oracle is characterized as a <em>ḥāzôn</em> (vision) rather than merely a verbal message, indicating a higher mode of revelation. <em>kᵉḵōl haddᵉḇārîm hāʾēlleh ûkᵉḵōl haḥāzôn hazzeh</em> — in keeping with all these words and the full vision: Nathan's faithfulness in transmission is noted.</p>",
    "16": "<p><em>wayyāḇōʾ hamelekh dāwid wayyēšeḇ lipnê YHWH</em> — King David went in and sat before the LORD. The posture of sitting (<em>yāšaḇ</em>) before the LORD is unusual — prayer is typically standing or prostrate. The sitting may indicate a prolonged audience or it may carry the connotation of dwelling in God's presence (the same verb, <em>yāšaḇ</em>, used of YHWH dwelling in his sanctuary). <em>mî ʾănî YHWH ʾĕlōhîm ûmî bêtî</em> — who am I, LORD God, and what is my house? — the humility formula standard in covenant responses (cf. Exod 3:11; Judg 6:15; 1 Sam 18:18).</p>",
    "17": "<p>The MT of this verse is difficult: <em>wattiqdaš zōʾt lᵉʿêneḵā hāʾĕlōhîm ûtᵉdabbēr ʿal-bêt-ʿaḇdᵉḵā lᵉmērāḥôq ûrᵉʾîtanî kᵉtôr hāʾādām hammaʿălāh</em>. The phrase <em>kᵉtôr hāʾādām hammaʿălāh</em> is obscure: possibly &ldquo;according to the manner of a man of high rank&rdquo; or &ldquo;like one exalted among men.&rdquo; The LXX differs significantly. The parallel in 2 Sam 7:19 reads <em>wᵉzōʾt tôrat hāʾādām</em> (and this is the charter/instruction for humanity) — an equally difficult phrase. The MKT renders it as &ldquo;the highest state of humanity&rdquo; — acknowledging the difficulty while capturing the sense that YHWH has honored David with something transcendent.</p>",
    "18": "<p><em>mah-yôsîp dāwid ʾēleḵā lᵉḵāḇôd ʾet-ʿaḇdᵉḵā wᵉʾattāh ʾet-ʿaḇdᵉḵā yādāʿtā</em> — what more can David say to you about the honor you have shown your servant? You know your servant. The verb <em>kābad</em> (to honor, make weighty) applied to God's action toward David inverts the normal direction: humans honor God; here God honors the human. <em>wᵉʾattāh ʾet-ʿaḇdᵉḵā yādāʿtā</em> — and you know your servant: <em>yādaʿ</em> here is the intimate knowing of covenant relationship, not merely cognitive awareness.</p>",
    "19": "<p><em>YHWH baʿăḇur ʿaḇdᵉḵā ûkᵉlibbᵉḵā ʿāśîtā ʾēt kol-haggᵉdûllāh hazzōʾt</em> — LORD, for your servant's sake and according to your own heart you have done this great thing. <em>kᵉlibbᵉḵā</em> (according to your heart) — YHWH acts from his own inner purpose and affection, not from external constraint. The phrase <em>ʾet kol-haggᵉdûllāh hazzōʾt</em> (all this greatness) is a summary exclamation for the entirety of the Davidic covenant oracle.</p>",
    "20": "<p><em>YHWH ʾên kāmôḵā wᵉʾên ʾĕlōhîm zûlātᵉḵā</em> — LORD, there is none like you, and there is no God besides you. The incomparability formula (<em>ʾên kāmôḵā</em>) is a standard confession of YHWH's uniqueness in the royal and prophetic literature (cf. Exod 15:11; 1 Kgs 8:23; Isa 40:18). The additional clause <em>wᵉʾên ʾĕlōhîm zûlātᵉḵā</em> (no God besides you) edges toward explicit monotheism — not merely that YHWH is superior among gods but that he is uniquely God.</p>",
    "21": "<p><em>ûmî kᵉʿammᵉḵā Yiśrāʾēl gôy ʾeḥād bāʾāreṣ</em> — and who is like your people Israel, one nation on earth? The incomparability extends from YHWH to Israel: as YHWH is incomparable among gods, Israel is incomparable among nations. <em>ʾăšer hālaḵ hāʾĕlōhîm liphôt lô ʿam</em> — whom God set out to redeem (<em>pādāh</em>, to redeem/ransom) as his own people. <em>nôrāʾôt</em> (awesome deeds) — the same term as v25 of the preceding psalm.</p>",
    "22": "<p><em>wattittēn ʾet-ʿammᵉḵā Yiśrāʾēl lᵉʿammᵉḵā ʿad-ʿôlām wᵉʾattāh YHWH hāyîtā lāhem lēʾlōhîm</em> — you established Israel as your own people forever, and you, LORD, became their God. The mutually constituting relationship: Israel is YHWH's people; YHWH is Israel's God. The covenant formula (<em>ʿam lî / YHWH lᵉʾlōhêhem</em>) appears throughout the covenant literature (Exod 6:7; Lev 26:12; Jer 31:33; Rev 21:3) as the summary of the entire covenant relationship.</p>",
    "23": "<p><em>wᵉʿattāh YHWH haddāḇār ʾăšer dibbartā ʿal-ʿaḇdᵉḵā wᵉʿal-bêtô yēʾāmēn ʿad-ʿôlām</em> — now LORD, let the word you spoke about your servant and his house stand firm forever. The verb <em>ʾāman</em> (hiphil: to be made firm, confirmed, reliable — the root of <em>ʾāmēn</em>) applied to the divine word: David asks that YHWH's word prove itself <em>ʾĕmûnāh</em> (faithfully true) in fulfillment.</p>",
    "24": "<p><em>wᵉyēʾāmēn wᵉyigdal šimḵā ʿad-ʿôlām</em> — may your name be made great forever. The connection between the covenant's stability and YHWH's reputation is explicit: the fulfillment of the Davidic promise is simultaneously a validation of YHWH's name. <em>YHWH ṣᵉḇāʾôt ʾĕlōhê Yiśrāʾēl ʾĕlōhîm lᵉYiśrāʾēl</em> — LORD of Hosts, God of Israel, God to Israel: the triple divine title emphasizes YHWH's comprehensive identity as both cosmic sovereign and covenantal partner.</p>",
    "25": "<p><em>kî-ʾattāh ʾĕlōhay gillîtā ʾet-ʾōzen ʿaḇdᵉḵā libᵉnôt-lô bayit</em> — for you, my God, have revealed to your servant that you will build him a house. <em>gillāh ʾōzen</em> (uncovered the ear, revealed) — the idiom for private disclosure of privileged information (1 Sam 20:2; 2 Sam 7:27). The uncovering of the ear is an intimate act: YHWH has taken David into his confidence about his own plans. <em>ʿal-kēn māṣāʾ ʿaḇdᵉḵā lᵉhitpallēl lᵉpāneḵā</em> — that is why your servant has found it possible to pray before you: the prayer is not a request but a response to prior revelation.</p>",
    "26": "<p><em>wᵉʿattāh YHWH ʾattāh-hûʾ hāʾĕlōhîm wattidabbēr ʾet-hattôḇāh hazzōʾt ʾel-ʿaḇdᵉḵā</em> — now LORD, you are God (<em>ʾattāh-hûʾ hāʾĕlōhîm</em> — an identification formula: you are the one who is God), and you have spoken this good thing to your servant. The affirmation grounds the following petition: because YHWH is God and has spoken, his word will be fulfilled.</p>",
    "27": "<p><em>wᵉʿattāh hôʾalt lᵉḇārēk ʾet-bêt ʿaḇdᵉḵā lihyôt lᵉʿôlām lᵉpāneḵā</em> — now please be pleased to bless the house of your servant, that it may stand before you forever. <em>hôʾalt</em> — the hiphil of <em>yāʾal</em> (to be willing, be pleased to) — David asks that YHWH's willingness (<em>rāṣôn</em> in concept) express itself in blessing. <em>kî-ʾattāh YHWH bēraḵtā ûmᵉḇōrāḵ yihyeh lᵉʿôlām</em> — for you, LORD, have blessed it, and it will be blessed forever: the prayer closes on certainty — what YHWH has blessed remains blessed.</p>"
  },
  "18": {
    "1": "<p>The summary of David's campaigns in ch18 closely parallels 2 Sam 8:1-18. The Chronicler preserves these accounts to demonstrate that the conditions necessary for the temple — political security and the accumulation of materials (v8, 11) — were fulfilled during David's reign. <em>wayyaḵ dāwid ʾet-Pᵉlišṭîm wayyiknaʿēm</em> — David defeated the Philistines and subdued them. <em>kānaʿ</em> (hiphil: to humble, subdue) — the same verb applied to Israel's enemies that YHWH promised in 17:10.</p>",
    "2": "<p><em>wayyaḵ ʾet-Mōʾāḇ wayyihyû Môʾāḇ ʿăḇādîm lᵉḏāwid nōśᵉʾê minḥāh</em> — the Moabites became his subjects (<em>ʿăḇādîm</em>, servants) bringing tribute (<em>minḥāh</em>). The term <em>minḥāh</em> (tribute/gift-offering) is also the standard term for the grain offering in the cultic system; its use here for tribute payment from a subjugated nation is a reminder that political submission and cultic offerings share the same vocabulary of acknowledgment.</p>",
    "3": "<p><em>wayyaḵ dāwid ʾet-Hadadezer melek Ṣôḇāh hamātāh bᵉlektô lihyaṣṣîb yādô binhār-Pᵉrāt</em> — David defeated Hadadezer king of Zobah near Hamath when Hadadezer went to extend his hand to the Euphrates River. The Aramean kingdom of Zobah was located north of Damascus in the Beqa valley. The phrase <em>lihyaṣṣîb yādô</em> (to set up his hand/stele) refers to erecting a victory monument — Hadadezer was on a northern campaign that David intercepted.</p>",
    "4": "<p><em>wayyiqqaḥ dāwid mimmennû ʾelep merkāḇôt</em> — David captured a thousand of his chariots. The most significant detail: <em>wayᵉʿaqqēr dāwid ʾet-kol-harekeb wayotēr mimmennû mēʾāh rekeb</em> — David hamstrung (<em>ʿiqqēr</em>) all the chariot horses, keeping only a hundred. The hamstringing of horses was commanded by Moses (Deut 17:16-17: the king must not multiply horses) — David's compliance with this law even in military victory shows his covenantal faithfulness and trust in YHWH rather than military technology.</p>",
    "5": "<p>The Syrians of Damascus come to aid Hadadezer but David defeats 22,000 of them. <em>ʾĂrām Dammeśeq</em> (Damascus Aram) — the Aramean city-state of Damascus, which will become Israel's major antagonist in the 9th-8th centuries. Their intervention and defeat marks the beginning of David's empire extending into what is now Syria.</p>",
    "6": "<p><em>wayyāśem dāwid biʾĂrām Dammeśeq</em> — David stationed garrisons (<em>neṣîḇîm</em>, military posts) throughout Damascus Aram. The garrisons convert the territory from a defeated enemy into a controlled province bringing tribute. <em>wayyôšaʿ YHWH ʾet-dāwid bᵉḵōl ʾăšer hālaḵ</em> — the LORD gave David victory wherever he went: the theological refrain that punctuates the military summary (cf. vv13, 14; 17:8).</p>",
    "7": "<p><em>wayyiqqaḥ dāwid ʾēt šiltê hazāhāḇ ʾăšer hāyû ʾal ʿaḇdê Hadadezer</em> — David took the golden shields (<em>šiltê hazāhāḇ</em>, gold quivers or shields) carried by Hadadezer's officers. These luxury items of warfare — gold shields would be ceremonial rather than functional — are brought to Jerusalem, consecrating the spoils of conquest to the city that will house the temple. Their later use as temple ornamentation (implied by v11) materializes the connection between military victory and sacred building.</p>",
    "8": "<p><em>ûmiTibḥat ûmikKûn ʾārê Hadadezer hēḇîʾ dāwid nᵉḥōšet harbēh ʾăšer ʿāśāh Šᵉlōmōh ʾet-hayyām hannᵉḥōšet wᵉʾet-hāʿammûdîm wᵉʾēt kᵉlê hannᵉḥōšet</em> — from Tibhath and Chun, David brought large quantities of bronze — from which Solomon later made the bronze sea, the pillars, and the bronze vessels. The Chronicler explicitly connects David's military spoil with Solomon's temple furnishings — a connection not explicit in 2 Sam 8:8. This is a characteristic Chronicler technique: showing that David's entire reign was preparation for the temple.</p>",
    "9": "<p>Tou king of Hamath (<em>Tōʿû melek Ḥamāt</em>) is the Syrian king of the city-state north of Zobah. <em>šāmaʿ</em> — when he heard that David had struck down the entire army of Hadadezer — the verb <em>šāmaʿ</em> (to hear, obey) triggering Tou's diplomatic response: he heard; therefore he acted. International relations in the ancient Near East operated on the news of military success spreading to neighboring states.</p>",
    "10": "<p>Tou sends his son Hadoram (<em>Hādôrām</em>, corresponding to <em>Jôrām</em> in 2 Sam 8:10 — a variant name) to greet David and congratulate him. The sending of a son rather than an ambassador signals the highest diplomatic courtesy. The gifts — <em>kᵉlê-zāhāḇ wᵉḵesep ûnᵉḥōšet</em> (articles of gold, silver, and bronze) — follow the standard tribute hierarchy (gold > silver > bronze) used throughout Ch17-18 for cataloging dedicated wealth.</p>",
    "11": "<p><em>ʾōtām gam-hēmmāh hiqqdîš hammelek dāwid laYHWH</em> — King David dedicated all of this to the LORD. <em>qiddaš</em> (piel of <em>qādaš</em>, to consecrate, make holy) — the wealth from all David's campaigns is not merely stored but consecrated (<em>hiqqdîš</em>) to divine use. The accumulation of consecrated materials establishes the treasury from which Solomon will build the temple (1 Chr 29:2-5).</p>",
    "12": "<p><em>wayyaḵ ʾĂḇîšay ben-Ṣᵉrûyāh ʾet-ʾĔdôm bᵉgêʾ-hammelaḥ šᵉmônat ʿāśār ʾālep</em> — Abishai son of Zeruiah killed 18,000 Edomites in the Valley of Salt. The <em>gêʾ-hammelaḥ</em> (Valley of Salt) was a battle site south of the Dead Sea, later the site of Amaziah's victory (2 Chr 25:11). The parallel in 2 Sam 8:13 attributes this victory to David himself; the Chronicler reassigns it to Abishai — possibly reflecting awareness of different source traditions or the complexity of command in a multi-front campaign.</p>",
    "13": "<p>Garrisons throughout Edom and the Edomites becoming David's subjects repeats the formula of v6 for Damascus. <em>wayyôšaʿ YHWH ʾet-dāwid bᵉḵōl ʾăšer hālaḵ</em> — the LORD gave David victory wherever he went: the second occurrence of the theological refrain (also at v6 and implied at v14). The phrase serves as a theological frame for what would otherwise read as a purely political-military account.</p>",
    "14": "<p><em>wayyimlōk dāwid ʿal-kol-Yiśrāʾēl wayyᵉhî ʿōśeh mišpāṭ ûṣᵉdāqāh lᵉḵol-ʿammô</em> — David reigned over all Israel and administered justice and equity to all his people. <em>mišpāṭ ûṣᵉdāqāh</em> — justice (<em>mišpāṭ</em>, legal decision, right judgment) and equity/righteousness (<em>ṣᵉdāqāh</em>, that which is right and straight) — the paired terms that define righteous governance in the prophetic vision of the ideal king (Isa 9:7; 11:4; Jer 22:3, 15; 33:15; Ezek 45:9). The Chronicler's summary of David's domestic governance matches the prophets' description of the coming Davidic king.</p>",
    "15": "<p>The administrative cabinet of David: <em>Yôʾāḇ ben-Ṣᵉrûyāh ʿal-haṣṣāḇāʾ</em> — Joab son of Zeruiah over the army. <em>wîhôšāpāṭ ben-ʾĂḥîlûd hammazkîr</em> — Jehoshaphat son of Ahilud, the royal herald (<em>mazkîr</em>, one who causes to remember — the royal recorder/secretary of state). The list of officials mirrors comparable lists in other ancient Near Eastern royal archives and signals David's establishment of a professional bureaucracy.</p>",
    "16": "<p><em>wᵉṢādôq ben-ʾĂḥîṭûḇ wăʾĂḇîmelek ben-ʾEḇyātār kōhănîm</em> — Zadok son of Ahitub and Abimelech son of Abiathar were priests. The parallel in 2 Sam 8:17 has &ldquo;Zadok son of Ahitub and Ahimelech son of Abiathar&rdquo; — the Chronicler reverses the first names of the two priests' sons, possibly reflecting a textual variant or a known confusion in the sources. Zadok will become Solomon's chief priest (1 Kgs 2:35). <em>wᵉŠawšāʾ sôpēr</em> — Shavsha was the scribe (<em>sôpēr</em>, the royal secretary/scribe), a key administrative position in ancient Near Eastern courts responsible for correspondence and record-keeping.</p>",
    "17": "<p><em>ûḇᵉnāyāhû ben-Yᵉhôyādāʿ ʿal-haKᵉrētî wᵉhaPᵉlētî</em> — Benaiah son of Jehoiada over the Cherethites and Pelethites. The <em>Kᵉrētî</em> (Cherethites) and <em>Pᵉlētî</em> (Pelethites) were David's elite bodyguard units, probably Philistine or Aegean mercenaries — the names may connect to Crete (<em>Kᵉrētîm</em>) and Philistia (<em>Pᵉlešet</em>). Using foreign mercenaries as a royal bodyguard was standard practice in ancient Near Eastern courts, providing a guard loyal to the king personally rather than to tribal or clan interests. <em>ûḇᵉnê dāwid hārīʾšōnîm lᵉyad-hammelek</em> — David's sons were chief officials at the king's side: the royal princes served as senior courtiers, a practice also attested in Egyptian and Assyrian royal households.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', '1chronicles')
    merge_comm(existing, CHRON1)
    save_comm('mkt-original', '1chronicles', existing)
    print('1 Chronicles 16–18 mkt-original written.')

if __name__ == '__main__':
    main()
